[SRSReportParameterAttribute(classStr(AslXyzNoteReportContract))]
public class AslXyzNoteReportDP extends SRSReportDataProviderBase
{
    AslXyzNoteReportTmp tmpTable;
}

Method.Source:
[SRSReportDataSetAttribute(tableStr(AslXyzNoteReportTmp))]
public AslXyzNoteReportTmp getAslXyzNoteReportTmp()
{
    select * from tmpTable;
    return tmpTable;
}

public void processReport()
{
    AslXyzNoteHeader noteHeader;

    delete_from tmpTable;

    insert_recordset tmpTable (NoteId, Subject)
        select NoteId, Subject
        from noteHeader;
}
